namespace sv_7d94a60856c04c3095e496d3ec13e63a.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@* Vertical tab navigation for settings sections *@

<nav class="settings-sidebar">
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="sidebar-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    min-width: 200px;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
}

.nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.75rem 1.25rem;
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    font-size: 0.95rem;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.nav-link:hover {
    background-color: #f8f9fa;
    color: #212529;
}

.nav-link.active {
    color: #0d6efd;
    background-color: #e7f1ff;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else if (_profile is not null)
    {
        <div class="row mb-4">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4 text-center">
                <div class="avatar-preview mb-2">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width:120px;height:120px;object-fit:cover;" />
                    }
                    else
                    {
                        <div class="avatar-placeholder rounded-circle">👤</div>
                    }
                </div>
                <small class="text-muted text-break">@_avatarUrl</small>
            </div>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade show" role="alert">
                ✅ Profile saved successfully!
            </div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }
    }
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
        _loading = false;
    }

    private void PopulateFields(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;

        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _showSuccess = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            PopulateFields(_profile);
        }
        _showSuccess = false;
        _errorMessage = null;
    }
}

.avatar-placeholder {
    width: 120px;
    height: 120px;
    background-color: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 3rem;
    margin: 0 auto;
}

@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notification Preferences</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading preferences…</p>
    }
    else
    {
        <div class="mb-4">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            @if (_allChannels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in _allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3" role="alert">✅ Preferences saved!</div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _allChannels = prefs.MutedChannels.ToList();
        _mutedChannels = prefs.MutedChannels.ToHashSet();
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;

        try
        {
            var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _showSuccess = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer;" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>

            @if (_validationError is not null)
            {
                <div class="alert alert-warning mt-3" role="alert">@_validationError</div>
            }

            @if (_showSuccess)
            {
                <div class="alert alert-success mt-3" role="alert">✅ Password updated!</div>
            }

            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private bool _showSuccess;
    private string? _validationError;
    private string? _errorMessage;

    private async Task UpdatePasswordAsync()
    {
        _validationError = null;
        _errorMessage = null;
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _validationError = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _validationError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _showSuccess = true;
            _currentPassword = "";
            _newPassword = "";
