                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                             OnRevokeRequested="ShowRevokeDialog" />

        <RevokeSessionDialog Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="CancelRevoke" />

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }
    }
