{"path": "/tmp/sv-7d94a60856c04c3095e496d3ec13e63a/Components/Pages/Settings/SecuritySection.razor", "file_text": "@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (_lastPasswordChange.HasValue)
                    {
                        <p class="text-muted mt-2 mb-0">
                            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </p>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                             OnRevokeRequested="ShowRevokeDialog" />

        <RevokeSessionDialog Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="CancelRevoke" />

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _errorMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}
"}

{"path": "/tmp/sv-7d94a60856c04c3095e496d3ec13e63a/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success mt-3" role="alert">✅ Appearance saved!</div>
                }

                @if (_errorMessage is not null)
                {
                    <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
                }
            </div>

            @* Live preview panel *@
            <div class="col-md-5">
                <div class="card">
                    <div class="card-header">Live Preview</div>
                    <div class="card-body @PreviewClass()" style="@PreviewStyle()">
                        <h6 style="margin-bottom: 0.5rem;">Preview Title</h6>
                        <p style="margin-bottom: 0.5rem;">
                            This is how your content will look with the selected settings.
                        </p>
                        <button class="btn btn-sm btn-primary">Sample Button</button>
                        <div class="mt-2">
                            <span class="badge bg-info">Tag</span>
                            <span class="badge bg-secondary ms-1">Label</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewStyle()
    {
        var bg = _theme switch
        {
            "Dark" => "background:#1e1e1e; color:#d4d4d4;",
            "System" => "background:#f0f0f0; color:#333;",
            _ => "background:#fff; color:#212529;"
        };

        var fs = _fontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.2rem;",
            _ => "font-size:1rem;"
        };

        var padding = _compactMode ? "padding:0.5rem;" : "padding:1rem;";

        return $"{bg} {fs} {padding} transition: all 0.2s ease;";
    }

    private string PreviewClass() => _compactMode ? "compact-preview" : "";

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        _errorMessage = null;

        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _showSuccess = true;
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

