@using sv_7d94a60856c04c3095e496d3ec13e63a.Models

@if (Session is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal d-block fade show" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@Session.Device</strong> from <strong>@Session.Location</strong>?
                    </p>
                    <p class="text-muted">This will sign the device out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public ActiveSession? Session { get; set; }

    [Parameter]
    public EventCallback OnConfirm { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_7d94a60856c04c3095e496d3ec13e63a.Models

<div class="mb-4">
    <h5>Active Sessions</h5>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => OnRevokeRequested.InvokeAsync(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = new();

    /// <summary>The ID of the current browser session, which cannot be revoked.</summary>
    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter]
    public EventCallback<ActiveSession> OnRevokeRequested { get; set; }
}

@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security Settings</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (_lastPasswordChange.HasValue)
                    {
                        <p class="text-muted mt-2 mb-0">
                            Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </p>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                             OnRevokeRequested="ShowRevokeDialog" />

        <RevokeSessionDialog Session="_sessionToRevoke"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="CancelRevoke" />

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private ActiveSession? _sessionToRevoke;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _errorMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

