@using sv_7d94a60856c04c3095e496d3ec13e63a.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        <option value="en">English</option>
                        <option value="es">Español</option>
                        <option value="fr">Français</option>
                        <option value="de">Deutsch</option>
                        <option value="ja">日本語</option>
                        <option value="zh">中文</option>
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>

                @if (_showSuccess)
                {
                    <div class="alert alert-success mt-3" role="alert">✅ Appearance saved!</div>
                }

                @if (_errorMessage is not null)
                {
                    <div class="alert alert-danger mt-3" role="alert">@_errorMessage</div>
                }
            </div>

            @* Live preview panel *@
            <div class="col-md-5">
                <div class="card">
                    <div class="card-header">Live Preview</div>
                    <div class="card-body @PreviewClass()" style="@PreviewStyle()">
                        <h6 style="margin-bottom: 0.5rem;">Preview Title</h6>
                        <p style="margin-bottom: 0.5rem;">
                            This is how your content will look with the selected settings.
                        </p>
                        <button class="btn btn-sm btn-primary">Sample Button</button>
                        <div class="mt-2">
                            <span class="badge bg-info">Tag</span>
                            <span class="badge bg-secondary ms-1">Label</span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;
    private string? _errorMessage;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string PreviewStyle()
    {
        var bg = _theme switch
        {
            "Dark" => "background:#1e1e1e; color:#d4d4d4;",
            "System" => "background:#f0f0f0; color:#333;",
            _ => "background:#fff; color:#212529;"
        };

        var fs = _fontSize switch
        {
            "Small" => "font-size:0.8rem;",
            "Large" => "font-size:1.2rem;",
            _ => "font-size:1rem;"
        };

        var padding = _compactMode ? "padding:0.5rem;" : "padding:1rem;";

        return $"{bg} {fs} {padding} transition: all 0.2s ease;";
    }

    private string PreviewClass() => _compactMode ? "compact-preview" : "";

